VALUES
  ('heelevel3-53250add-moex-00102', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '行政機關所為下列行為，何者直接對外發生法律效力？', '["土地登記簿標示部其他登記事項欄中「本土地涉及違法地目變更，土地使用管制仍應受原『田』 地目之限制」之註記", "人民團體經核准立案後，將選任職員簡歷冊報請主管機關核備", "戶政機關以催告函通知甲辦理戶籍撤銷登記，否則將依法逕為登記", "公務人員經評定年終考績考列丙等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00103', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '教育部對於私立大學停聘其教師之核准，其法律性質為何？', '["形成私法效果之行政處分", "對人一般處分", "對物一般處分", "事實行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00104', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於處分機關救濟期間之告知，下列敘述何者錯誤？', '["處分機關未告知救濟期間，致相對人或利害關係人遲誤者，如自處分書送達後1年內聲明不服 時，視為於法定期間內所為", "處分機關告知之救濟期間有錯誤時，應由該機關以通知更正之，並自通知送達之翌日起算法定 期間", "處分機關告知之救濟期間較法定期間為長者，處分機關雖以通知更正，如相對人或利害關係人 信賴原告知之救濟期間，致無法於法定期間內提起救濟，而於原告知之期間內為之者，視為於 法定期間內所為", "處分機關告知之救濟期間錯誤未為更正，致相對人或利害關係人遲誤者，如自處分書送達後 3 年內聲明不服時，視為於法定期間內所為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00105', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '衛生福利部中央健康保險署與各醫事服務機構締結全民健康保險特約醫事服務機構合約，若雙方 對於該合約內容有爭議時，應向下列何者尋求救濟？', '["憲法法庭", "交通法庭", "行政法院", "地方法院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00106', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於給付行政與法律保留原則之關係，下列敘述何者正確？', '["給付行政不適用法律保留原則", "給付行政一律適用法律保留原則", "給予中小學生成績優良獎勵，應經地方立法機關制定自治條例作為依據", "給付行政如涉及公共利益之重大事項者，應有法律或法律明確之授權為依據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00107', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '一行為同時違反三項行政法義務規定。A規定：罰鍰3,000元至6,000元，沒入實施違法行為的器 械設備；B規定：罰鍰2,500元至4,000元；C規定：罰鍰1,500元至8,000元，並應參加6小時 講習。主管機關所為裁罰，下列何者正確？', '["裁處罰鍰不得超過6,000元，且一併裁處沒入及講習", "裁處罰鍰不得低於2,500元，且不得一併裁處其他種類處罰", "裁處罰鍰不得低於3,000元，且得一併裁處沒入及講習", "應就三項規定分別裁處罰鍰，且一併裁處沒入及講習"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00108', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '甲欠繳稅款，經稽徵機關催繳不理後移送該管行政執行分署執行。該管行政執行分署因而將甲名 下之房屋予以查封。甲對該執行命令不服，而欲提起救濟，下列敘述何者正確？', '["甲得依稅捐稽徵法第35條規定，對該執行命令申請復查", "甲得依行政執行法第9條規定，對該執行命令聲明異議，遭駁回後提起訴願", "甲得依行政執行法第9條規定，對該執行命令聲明異議，遭駁回後直接提起行政訴訟", "甲得依訴願法第1條第1項規定，直接對該執行命令提起訴願 33150"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00109', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '依行政程序法規定，下列敘述何者錯誤？', '["舉行聽證應預先公告者，行政機關應將法定相關事項，登載於政府公報或以其他適當方法公告之", "行政機關將其權限之一部分委任或委託，應將該事項及法規依據公告之，並刊登政府公報或新 聞紙", "行政機關經裁併之公告事項，自公告之日起算至第3日起發生移轉管轄權之效力", "當事人或利害關係人得向行政機關申請閱覽有關資料或卷宗，但以主張其事實上利益有必要者 為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00110', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於訴願決定，下列敘述何者錯誤？', '["未經法定先行程序而逕行提起訴願之案件，嗣後亦未補正者，應作成不受理之決定", "訴願案件雖符合程式要件，惟實體上無理由，應作成駁回訴願之決定", "對於違法或不當行政處分提起訴願而有理由者，應作成撤銷原處分之決定，並視情形發回原處 分機關另為處分或自為變更原處分", "對於行政機關怠為處分而提起訴願者，應作成確認原處分機關違法之決定，並自為一定之處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00111', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '臺東縣政府函成功鎮公所代為公告現有巷道，甲所有之土地屬於該現有巷道之一部分，下列敘述 何者正確？', '["認定現有巷道之主管機關為臺東縣成功鎮公所", "認定現有巷道之公告，自公告日起第3日生效", "現有巷道之認定，涉及人民財產權之限制，因行政處分未個別送達給相對人甲，故對甲不生效力", "甲不服該公告應向內政部提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "28515c92bb6f", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL)
